var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"여기가 북방의 연구소구나… 생각보다 평범하네.","JPN":"ここが北方の研究所……思ったより普通だね。","ENG":"So this is the Northern Union's research lab... It's more ordinary than I thought.","TWN":"這裡就是北方和議會的研究所嗎……看起來比想像中普通呢。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SCIENCE_DOLL_NPC_NULL","text":{"KOREA":"미안해. 우리들이 일하는 곳은 기밀이라서, 그곳까지 보여주기는 힘들단다.","JPN":"ごめんね。私たちが仕事をしてるところは機密だから、そこは見せてあげられないよ。","ENG":"Sorry. I can't show you the place where we work since it's confidential.","TWN":"抱歉。我們工作的地方是機密，不能帶你去看。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SCIENCE_DOLL_NPC_NULL","text":{"KOREA":"그래도 자주 놀러 와줄래? 우린 얼마든지 환영이야.","JPN":"でも、これからは遊びに来てくれない？　私たちはいくらでも歓迎だよ。","ENG":"But will you come visit us often to play? You're always welcome to.","TWN":"不過你能常來玩嗎？我們隨時歡迎你。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"그, 그럼 정말 나도 입대할 수 있는 거야?","JPN":"じゃ、じゃあ、本当に私も入隊できるの？","ENG":"D-does that mean I can enlist?","TWN":"那，那我真的也能參軍嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SCIENCE_DOLL_NPC_NULL","text":{"KOREA":"음… 그건 아마도….","JPN":"うーん……それはたぶん……","ENG":"Mm... I think...","TWN":"嗯……可能……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"연구원 언니? 이 아이는 누군가요?","JPN":"研究員さん？　この子は誰ですか？","ENG":"Hey? Who's the little girl?","TWN":"研究員姊姊？這個孩子是誰？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SCIENCE_DOLL_NPC_NULL","text":{"KOREA":"드레카바크구나. 소년병이 되고 싶다고 찾아온 아이야.","JPN":"ドレカバクか。少年兵になりたいって来た子だよ。","ENG":"Oh, Drekavac. She came here wanting to become a child soldier.","TWN":"原來是德蕾卡娃克，她是個想成為少年兵的孩子。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SCIENCE_DOLL_NPC_NULL","text":{"KOREA":"그래서 연구소 내부 좀 구경시켜 주고 있었어.","JPN":"だから、研究所の内部を案内していたところ。","ENG":"So I was just giving her a little tour.","TWN":"所以我帶她參觀了一下研究所內部。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SCIENCE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그랬구나… 후훗.","JPN":"そうだったんだ……ふふっ。","ENG":"Is that so...? Haha.","TWN":"原來如此……呵呵。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"아, 안녕…?","JPN":"こ、こんにちは……？","ENG":"H-hi...","TWN":"你，你好……？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"안녕? 난 드레카바크라고 해.","JPN":"こんにちは。私はドレカバクよ。","ENG":"Hi. I'm Drekavac.","TWN":"你好？我叫德蕾卡娃克。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"어? 언니도 군인이야?","JPN":"あれ？　お姉さんも軍人なの？","ENG":"Oh? Are you a soldier too?","TWN":"嗯？姊姊你也是軍人嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"아~ 포스터 봤어! 거기 나왔던 언니구나!","JPN":"あ～ポスター見たよ！　あそこに出てたお姉さんだ！","ENG":"Oh! I know you! I saw you on the poster!","TWN":"啊～我知道了！你是海報上的姊姊！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 그걸 봤구나? 알아봐 줘서 고마워.","JPN":"ひひっ、あれを見たんだ？　知っててくれてありがとう。","ENG":"Hehe! You saw that? Thanks for noticing me.","TWN":"嘻嘻，被你發現了？謝謝你認出來了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"너도 나처럼 되고 싶어서 왔니?","JPN":"あなたも私みたいになりたくて来たの？","ENG":"So, you came here to become like me?","TWN":"你是想變得和我一樣才來的嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"응! 나도 강해지고 싶어!","JPN":"うん！　私も強くなりたい！","ENG":"Uh-huh! I want to get stronger!","TWN":"嗯！我也想變強！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"정말 멋지다… 넌 뭘 할 수 있어?","JPN":"わあ、カッコいいね……あなたは何ができる？","ENG":"That's so cool... So, what are you good at?","TWN":"真厲害……你能做什麼？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"나, 나?","JPN":"わ、私？","ENG":"M-me?","TWN":"我，我嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"난 다리가 튼튼하고 빨라! 그래서 누구한테도 잡혀본 적 없어!","JPN":"私は足が丈夫で速いの！　だから、誰にも捕まったことないんだ！","ENG":"I have strong and fast legs! I've never been caught by anyone before!","TWN":"我的腿很結實，而且跑得很快！所以從來沒有被任何人抓住過！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"헤헷, 매번 엄마가 잡으려 해도, 지금까지 한 번도 안잡혔다구!","JPN":"へへっ、お母さんが捕まえようとしても、今まで一度も捕まったことないし！","ENG":"Hehe. Mom keeps chasing me, but I've never been caught by her once!","TWN":"嘿嘿，每次媽媽想抓住我，到現在也一次都沒成功過！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"꼭 강한 병사가 돼서 엄마 코를 납작하게 만들어줄 거야!","JPN":"絶対強い兵士になって、お母さんの鼻をペチャンコにしてやる！","ENG":"I want to become a strong soldier and take my mom down a peg!","TWN":"我一定會成為強大的戰士，讓媽媽大吃一驚！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"와~ <color=#ff3636>납작하게?</color> 정말 대단하다.","JPN":"わあ～<color=#ff3636>ペチャンコに？</color>　本当にすごいね。","ENG":"Wow! <color=#ff3636>Take your mom down</color>, eh? That's amazing.","TWN":"哇~<color=#ff3636>大吃一驚？</color>真了不起。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그럼… 우리 술래잡기 하면서 놀까? 너랑 친하게 지내고 싶어.","JPN":"じゃあ……私たち、鬼ごっこして遊ぶ？　あなたと仲良くなりたいの。","ENG":"Then... do you want to play tag with me? I want to be your friend.","TWN":"那麼……我們來玩捉迷藏吧？我想和你親近一些。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"하핫, 아무리 언니라도 날 잡는 건 무리일걸? 난 마을에서 가장 빠르다구!","JPN":"ははっ、いくらお姉さんでも、私を捕まえるのは無理だよ。私は村で一番速いんだから！","ENG":"Haha! I don't think even you can catch me! I'm the fastest in the village!","TWN":"哈哈，就算是姊姊也抓不到我的喔？我是村裡跑得最快的！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그렇구나. 그럼 언니 힘낼게?","JPN":"そっか。じゃあ、お姉さん頑張るね？","ENG":"Are you, now? Then, I guess I'll have to give it my all.","TWN":"是嗎？那姊姊會加油的，好嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"에잇♪","JPN":"えいっ♪","ENG":"Yoink♪","TWN":"嘿咻♪"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};